Debounce delays calling a function until a certain time has passed since the last invocation, preventing it from running too frequently.

```javascript
function debounce(fn, wait = 300) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => fn.apply(context, args), wait);
  };
}

// Example: debounce an input handler so it runs 300ms after typing stops
const input = document.querySelector('#search');
const handleSearch = (query) => {
  // perform search or API call
  console.log('Searching for', query);
};
const debouncedSearch = debounce(handleSearch, 300);

input.addEventListener('input', (e) => debouncedSearch(e.target.value));
```
